query:
mutation sitesUpdateSecondaryGcpVSocket ( $accountId:ID! $updateSecondaryGcpVSocketInput:UpdateSecondaryGcpVSocketInput!) {
	sites ( accountId:$accountId ) {
		updateSecondaryGcpVSocket ( input:$updateSecondaryGcpVSocketInput  )  {
			socketInfo {
				site {
					id
					name
				}
				id
				interfaceIp
				loadBalancerIp
			}
		}
	}	
}
